import React, {useState} from "react";

function VideoCard({videoUrl, title, description, h, w}) {

  const [modal, setModal] = useState(false);
  const [videoLoading, setVideoLoading] = useState(true);

  function openModal(){
    setModal(!modal);
  };

  return (
  <div
    onClick={openModal}
    className="">
      {modal ? (
          <section className="">
            <div className="">
              <div className="" modal={modal}>
                <button
                  className=""
                  onClick={setModal}
                >X</button>
                <div className="">
                  {
                    <iframe 
                        width="560" 
                        height="315" 
                        src="https://www.youtube.com/embed/yPpuQS50k24?si=wa1D2E12EP28JgVU" 
                        title="YouTube video player" 
                        frameborder="0" 
                        allow="accelerometer; 
                        autoplay; 
                        clipboard-write; 
                        encrypted-media; 
                        gyroscope; 
                        picture-in-picture; 
                        web-share" 
                        referrerpolicy="strict-origin-when-cross-origin" 
                        allowfullscreen>
                    </iframe>
                  }
                </div>
              </div>
            </div>
          </section>
        ) : null}
    </div>
  );
}

export default VideoCard;
